      await waitFor(() => alertMessage);

      assert.equal(alertMessage?.trim().replace(/[.,?!]+$/g, '').toLowerCase(), 'creature not found');
    } else {
      assert.fail();
    }
  } catch (err) {
    throw new Error(err);
  }

